#include <iostream>
#include <queue>
#include <vector>

using namespace std;
class Solution {
public:
    queue<int> q;

    void enqueue(vector<int>& nums) {
        for (int num : nums)
            q.push(num);
    }

    int dequeue() {
        if (q.size() == 0) throw runtime_error("pop from an empty queue");
        int res = q.front();
        q.pop();
        return res;
    }
};

int main() {
    Solution s;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) cin >> nums[i];
    s.enqueue(nums);
    for (int i = 0; i < n; ++i) cout << s.dequeue() << endl;
    return 0;
}
